class CodeGenProgram(dspy.Module):
    def __init__(self):
        super().__init__()
        self.writer = dspy.ChainOfThought(CodeWriter)
        self.tester = dspy.ChainOfThought(CodeTester)
        self.refiner = dspy.ChainOfThought('previous_code, test_results -> refined_code')

    def forward(self, task, test_cases, max_iters=3):
        code = self.writer(task_description=task, test_cases=test_cases).code
        for i in range(max_iters):
            results = self.tester(code=code, test_cases=test_cases).test_results
            if 'PASS' in results:
                return dspy.Prediction(code=code)
            code = self.refiner(previous_code=code, test_results=results).refined_code
        return dspy.Prediction(code=code)

